mapper.select:
SELECT
    s.id AS supplierId,
    s.name AS supplierName,
    IFNULL(pin.in_total, 0) AS inPrice,
    IFNULL(prt.return_total, 0) AS returnPrice,
    (IFNULL(pin.in_total, 0) - IFNULL(prt.return_total, 0)) AS netPrice
FROM erp_supplier s
LEFT JOIN (
    SELECT supplier_id, SUM(total_price) AS in_total
    FROM erp_purchase_in
    WHERE deleted = 0
     AND in_time >= #{beginTime} 
     AND in_time < #{endTime} 

        AND tenant_id = ${@nova.erp.framework.tenant.core.context.TenantContextHolder@getTenantId()}

    GROUP BY supplier_id
) pin ON s.id = pin.supplier_id
LEFT JOIN (
    SELECT supplier_id, SUM(total_price) AS return_total
    FROM erp_purchase_return
    WHERE deleted = 0
     AND return_time >= #{beginTime} 
     AND return_time < #{endTime} 

        AND tenant_id = ${@nova.erp.framework.tenant.core.context.TenantContextHolder@getTenantId()}

    GROUP BY supplier_id
) prt ON s.id = prt.supplier_id
WHERE s.deleted = 0
 AND s.id = #{supplierId} 

    AND s.tenant_id = ${@nova.erp.framework.tenant.core.context.TenantContextHolder@getTenantId()}

HAVING inPrice > 0 OR returnPrice > 0
ORDER BY netPrice DESC

SELECT
    c.id AS customerId,
    c.name AS customerName,
    IFNULL(so.out_total, 0) AS outPrice,
    IFNULL(sr.return_total, 0) AS returnPrice,
    (IFNULL(so.out_total, 0) - IFNULL(sr.return_total, 0)) AS netPrice
FROM erp_customer c
LEFT JOIN (
    SELECT customer_id, SUM(total_price) AS out_total
    FROM erp_sale_out
    WHERE deleted = 0
     AND out_time >= #{beginTime} 
     AND out_time < #{endTime} 

        AND tenant_id = ${@nova.erp.framework.tenant.core.context.TenantContextHolder@getTenantId()}

    GROUP BY customer_id
) so ON c.id = so.customer_id
LEFT JOIN (
    SELECT customer_id, SUM(total_price) AS return_total
    FROM erp_sale_return
    WHERE deleted = 0
     AND return_time >= #{beginTime} 
     AND return_time < #{endTime} 

        AND tenant_id = ${@nova.erp.framework.tenant.core.context.TenantContextHolder@getTenantId()}

    GROUP BY customer_id
) sr ON c.id = sr.customer_id
WHERE c.deleted = 0
 AND c.id = #{customerId} 

    AND c.tenant_id = ${@nova.erp.framework.tenant.core.context.TenantContextHolder@getTenantId()}

HAVING outPrice > 0 OR returnPrice > 0
ORDER BY netPrice DESC

SELECT p.id AS productId, p.name AS productName, w.name AS warehouseName, s.count AS currentStock, IFNULL(p.safe_stock, 10) AS safeStock, (IFNULL(p.safe_stock, 10) - s.count) AS gapCount FROM erp_stock s INNER JOIN erp_product p ON s.product_id = p.id AND p.deleted = 0 INNER JOIN erp_warehouse w ON s.warehouse_id = w.id AND w.deleted = 0 WHERE s.count < IFNULL(p.safe_stock, 10) AND s.deleted = 0
AND s.tenant_id = ${@nova.erp.framework.tenant.core.context.TenantContextHolder@getTenantId()}
ORDER BY gapCount DESC

SELECT o.order_no AS orderNo, c.transport_cost AS transportCost, c.fuel_cost AS fuelCost, c.toll_cost AS tollCost, c.other_cost AS otherCost, c.total_cost AS totalCost FROM logistics_cost c INNER JOIN logistics_order o ON c.logistics_order_id = o.id AND o.deleted = 0 WHERE c.deleted = 0 AND c.create_time >= #{beginTime} AND c.create_time < #{endTime}
AND c.tenant_id = ${@nova.erp.framework.tenant.core.context.TenantContextHolder@getTenantId()}
ORDER BY c.create_time DESC
